def _rel_l2(a, b):
    a, b = np.asarray(a, np.float64).ravel(), np.asarray(b, np.float64).ravel()
    if a.shape != b.shape: return float('inf')
    return float(np.linalg.norm(a - b) / (np.linalg.norm(b) + 1e-8))

def _pytorch_eager():
    import onnx, onnx2torch, torch
    m = onnx2torch.convert(onnx.load(_io.BytesIO(_ONNX_BYTES))).eval()
    with torch.no_grad():
        out = m(torch.from_numpy(INPUT))
    if isinstance(out, (list, tuple)): out = out[0]
    return out.float().numpy().ravel()

def main():
    try:
        ref = _pytorch_eager()
    except Exception as e:
        print(f"[error] pytorch_eager reference failed: {e}")
        sys.exit(2)

    try:
        import openvino.runtime as ov
        core = ov.Core()
        compiled = core.compile_model(core.read_model(_io.BytesIO(_ONNX_BYTES), weights=b""), "CPU")
        infer = compiled.create_infer_request()
        infer.infer({0: INPUT})
        result = infer.get_output_tensor(0).data.ravel()
    except ImportError:
        print("OpenVINO not installed — cannot verify")
        sys.exit(2)
    except Exception as e:
        print(f"[crash] openvino: {e}")
        sys.exit(0)

    diff = _rel_l2(result, ref)
    print(f"Expected (pytorch_eager) at idx 1301: {ref.ravel()[1301]:.6f}")
    print(f"Got (OpenVINO CPU) at idx 1301: {result.ravel()[1301]:.6f}")  # expected=72.959892, got=0.754185
    print(f"rel L2(OV vs pytorch_eager) = {diff:.6e}")
    if diff > TOLERANCE:
        print("BUG REPRODUCED")
        sys.exit(0)
    print("not reproduced")
    sys.exit(1)

if __name__ == "__main__":
    main()
